function rollDie(sides) {
    return Math.ceil(Math.random() * sides);
}

function fromTable(roll, table) {
    return table.find(row => roll >= row.min && roll <= row.max)?.result;
}

const featureTable = [
    { min: 1, max: 3, result: "Landmark" },
{ min: 4, max: 4, result: "Settlement" },
{ min: 5, max: 5, result: "Lair" },
{ min: 6, max: 6, result: "Dungeon" }
];

const settlementTable = [
    { min: 1, max: 1, result: "Hamlet" },
{ min: 2, max: 2, result: "Village" },
{ min: 3, max: 3, result: "City" },
{ min: 4, max: 4, result: "Castle" },
{ min: 5, max: 5, result: "Tower" },
{ min: 6, max: 6, result: "Abbey" }
];

const landmarkTypeTable = [
    { min: 1, max: 3, result: "Natural Landmark" },
{ min: 4, max: 5, result: "Artificial Landmark" },
{ min: 6, max: 6, result: "Magic Landmark" }
];

const landmarkContentTable = [
    { min: 1, max: 1, result: "Hazard" },
{ min: 2, max: 3, result: "Empty" },
{ min: 4, max: 4, result: "Special" },
{ min: 5, max: 6, result: "Monsters" }
];

let featureRoll = rollDie(6);
let feature = fromTable(featureRoll, featureTable);

let output = `
<h2>Hex Contents</h2>
<p><b>Feature Roll:</b> d6 = ${featureRoll}</p>
<p><b>Feature:</b> ${feature}</p>
`;

if (feature === "Settlement") {
    let settlementRoll = rollDie(6);
    let settlement = fromTable(settlementRoll, settlementTable);

    output += `
    <hr>
    <p><b>Settlement Roll:</b> d6 = ${settlementRoll}</p>
    <p><b>Settlement Type:</b> ${settlement}</p>
    `;
}

if (feature === "Landmark") {
    let landmarkTypeRoll = rollDie(6);
    let landmarkType = fromTable(landmarkTypeRoll, landmarkTypeTable);

    let contentRoll = rollDie(6);
    let content = fromTable(contentRoll, landmarkContentTable);

    output += `
    <hr>
    <p><b>Landmark Type Roll:</b> d6 = ${landmarkTypeRoll}</p>
    <p><b>Landmark Type:</b> ${landmarkType}</p>

    <p><b>Content Roll:</b> d6 = ${contentRoll}</p>
    <p><b>Content:</b> ${content}</p>
    `;
}

ChatMessage.create({
    speaker: ChatMessage.getSpeaker(),
                   content: output
});
